<?php
/**
 * Template Name: Contact
 */
get_header(); the_post(); get_template_part( 'template-parts/page-hero' ); $phone = function_exists( 'wma_get_setting' ) ? wma_get_setting( 'phone' ) : ''; $email = function_exists( 'wma_get_setting' ) ? wma_get_setting( 'email' ) : ''; $address = function_exists( 'wma_get_setting' ) ? wma_get_setting( 'address' ) : ''; ?>
<section class="wma-section"><div class="wma-container wma-contact-grid"><div><span class="wma-eyebrow"><?php esc_html_e( 'Start a conversation', 'wild-morocco-adventures' ); ?></span><h2><?php esc_html_e( 'Tell us where your curiosity leads.', 'wild-morocco-adventures' ); ?></h2><div class="wma-rich-content"><?php the_content(); ?></div><dl class="wma-contact-list"><?php if ( $phone ) : ?><div><dt><?php esc_html_e( 'Call', 'wild-morocco-adventures' ); ?></dt><dd><a href="tel:<?php echo esc_attr( preg_replace( '/[^0-9+]/', '', $phone ) ); ?>"><?php echo esc_html( $phone ); ?></a></dd></div><?php endif; ?><?php if ( $email ) : ?><div><dt><?php esc_html_e( 'Email', 'wild-morocco-adventures' ); ?></dt><dd><a href="mailto:<?php echo esc_attr( antispambot( $email ) ); ?>"><?php echo esc_html( antispambot( $email ) ); ?></a></dd></div><?php endif; ?><?php if ( $address ) : ?><div><dt><?php esc_html_e( 'Visit', 'wild-morocco-adventures' ); ?></dt><dd><?php echo nl2br( esc_html( $address ) ); ?></dd></div><?php endif; ?></dl></div><div class="wma-form-card"><?php echo do_shortcode( '[wma_quote_form]' ); ?></div></div></section><?php get_footer(); ?>
